/* ─── INJECT CSS ─── */
function GlobalStyles() {
  useEffect(() => {
    const el = document.createElement("style");
    el.textContent = globalCSS;
    document.head.appendChild(el);
    return () => document.head.removeChild(el);
  }, []);
  return null;
}

/* ─── SCROLL ANIMATION HOOK ─── */
function useFadeUp() {
  useEffect(() => {
    const els = document.querySelectorAll(".fade-up");
    const obs = new IntersectionObserver(
      (entries) => entries.forEach((e) => { if (e.isIntersecting) e.target.classList.add("visible"); }),
      { threshold: 0.12 }
    );
    els.forEach((el) => obs.observe(el));
    return () => obs.disconnect();
  });
}

/* ─── NAVBAR ─── */
function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  const { pathname } = useLocation();

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 30);
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  // Close menu on route change
  useEffect(() => {
    setMenuOpen(false);
  }, [pathname]);

  const links = [
    { to: "/", label: "Home" },
    { to: "/services", label: "Services" },
    { to: "/projects", label: "Projects" },
    { to: "/blog", label: "Blog" },
    { to: "/contact", label: "Contact" },
  ];

  return (
    <nav style={{
      position: "fixed", top: 0, left: 0, right: 0, zIndex: 200,
      display: "flex", alignItems: "center", justifyContent: "space-between",
      padding: "0 5vw", height: "64px",
      background: scrolled || menuOpen ? "rgba(8,8,15,0.95)" : "transparent",
      borderBottom: scrolled || menuOpen ? `1px solid ${C.border}` : "1px solid transparent",
      backdropFilter: "blur(16px)",
      transition: "background 0.3s, border-color 0.3s",
    }}>
      <NavLink to="./" style={{ fontFamily: "'Syne',sans-serif", fontSize: "20px", fontWeight: 700, color: C.accent, letterSpacing: "-0.5px" }}>
        Dreamer<span style={{ color: C.text }}>.</span>
      </NavLink>

      {/* Desktop & Mobile Links */}
      <ul className={`nav-links ${menuOpen ? "open" : ""}`}>
        {links.map((l) => (
          <li key={l.to}>
            <NavLink
              to={l.to}
              end={l.to === "/"}
              className={({ isActive }) => isActive ? "nav-active" : ""}
              style={{ fontSize: "14px", color: C.muted, fontWeight: 400, transition: "color 0.2s" }}
            >
              {l.label}
            </NavLink>
          </li>
        ))}
      </ul>

      <div style={{ display: "flex", gap: "1rem", alignItems: "center" }}>
        <NavLink to="/contact" className="btn-primary hire-me-btn" style={{ fontSize: "13px", padding: "9px 20px", borderRadius: "8px" }}>
          Hire Me
        </NavLink>

        {/* Mobile Menu Hamburger */}
        <div className="mobile-menu-btn" onClick={() => setMenuOpen(!menuOpen)}>
          <svg width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
            {menuOpen ? <path d="M18 6L6 18M6 6l12 12" /> : <path d="M4 6h16M4 12h16M4 18h16" />}
          </svg>
        </div>
      </div>
    </nav>
  );
}

