/* ─── ANIMATED COUNTER COMPONENT ─── */
function AnimatedCounter({ target, duration = 1200 }) {
  const [count, setCount] = useState(0);
  const elementRef = useRef(null);
  const hasStarted = useRef(false);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        // التحقق من وصول الزائر للقسم وأن الأنميشن لم يبدأ بعد
        if (entries[0].isIntersecting && !hasStarted.current) {
          hasStarted.current = true;
          const numericValue = parseInt(target, 10) || 0;
          let startTimestamp = null;

          const step = (timestamp) => {
            if (!startTimestamp) startTimestamp = timestamp;
            const progress = Math.min((timestamp - startTimestamp) / duration, 1);

            setCount(Math.floor(progress * numericValue));

            if (progress < 1) {
              window.requestAnimationFrame(step);
            } else {
              setCount(numericValue); // التأكد من الوصول للرقم النهائي تماماً
            }
          };
          window.requestAnimationFrame(step);
        }
      },
      { threshold: 0.1 }
    );

    if (elementRef.current) {
      observer.observe(elementRef.current);
    }

    return () => observer.disconnect();
  }, [target, duration]);

  // استخراج العلامات المصاحبة مثل (+) أو (%) لإضافتها بجانب الرقم
  const suffix = target.replace(/[0-9]/g, '');

  return <span ref={elementRef}>{count}{suffix}</span>;
}


